package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class CadastroActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_cadastro)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainCadastro)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        findViewById<TextView>(R.id.txtVoltarLogin).setOnClickListener {
            finish()//fecha tela atual
        }

        findViewById<MaterialButton>(R.id.btnCriarContaCadastro).setOnClickListener {
            val nome = findViewById<TextInputEditText>(R.id.txtNome).text.toString().trim()
            val email = findViewById<TextInputEditText>(R.id.txtEmailCadastro).text.toString().trim()
            val senha = findViewById<TextInputEditText>(R.id.txtSenhaCadastro).text.toString()
            val confirmaSenha = findViewById<TextInputEditText>(R.id.txtConfirmarSenha).text.toString()

            // Validações
            when {
                nome.isEmpty() -> {
                    Toast.makeText(this, "Por favor, preencha o nome", Toast.LENGTH_SHORT).show()
                }
                email.isEmpty() -> {
                    Toast.makeText(this, "Por favor, preencha o email", Toast.LENGTH_SHORT).show()
                }
                !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                    Toast.makeText(this, "Email inválido", Toast.LENGTH_SHORT).show()
                }
                senha.isEmpty() -> {
                    Toast.makeText(this, "Por favor, preencha a senha", Toast.LENGTH_SHORT).show()
                }
                senha.length < 6 -> {
                    Toast.makeText(this, "Senha deve ter pelo menos 6 caracteres", Toast.LENGTH_SHORT).show()
                }
                confirmaSenha.isEmpty() -> {
                    Toast.makeText(this, "Por favor, confirme a senha", Toast.LENGTH_SHORT).show()
                }
                senha != confirmaSenha -> {
                    Toast.makeText(this, "As senhas não coincidem", Toast.LENGTH_SHORT).show()
                }
                else -> {
                    try {
                        val db = DatabaseHelper(this)
                        val novoUser = User(nome = nome, email = email, password = senha)
                        val id = db.insertUser(novoUser)
                        if (id != -1L) {
                            // Mostrar AlertDialog de sucesso
                            AlertDialog.Builder(this)
                                .setTitle("Sucesso!")
                                .setMessage("Conta criada com sucesso! Agora faça login com suas credenciais.")
                                .setPositiveButton("OK") { _, _ ->
                                    // Navegar para MainActivity (tela de login)
                                    startActivity(Intent(this, MainActivity::class.java))
                                    finish()
                                }
                                .setCancelable(false)
                                .show()
                        } else {
                            Toast.makeText(this, "Erro ao criar conta. Email pode estar duplicado.", Toast.LENGTH_SHORT).show()
                        }
                    } catch (e: Exception) {
                        Toast.makeText(this, "Erro: ${e.message}", Toast.LENGTH_SHORT).show()
                    }
                }
            }
        }
    }
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.button.MaterialButton
import com.google.android.material.textfield.TextInputEditText

class CadastroActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_cadastro)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainCadastro)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        findViewById<TextView>(R.id.txtVoltarLogin).setOnClickListener {
            finish()//fecha tela atual
        }

        findViewById<MaterialButton>(R.id.btnCriarContaCadastro).setOnClickListener {
            val nome = findViewById<TextInputEditText>(R.id.txtNome).text.toString().trim()
            val email = findViewById<TextInputEditText>(R.id.txtEmailCadastro).text.toString().trim()
            val senha = findViewById<TextInputEditText>(R.id.txtSenhaCadastro).text.toString()
            val confirmaSenha = findViewById<TextInputEditText>(R.id.txtConfirmarSenha).text.toString()

            // Validações
            var erroValidacao = false

            when {
                nome.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtNome).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o nome", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                email.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha o email", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                !android.util.Patterns.EMAIL_ADDRESS.matcher(email).matches() -> {
                    findViewById<TextInputEditText>(R.id.txtEmailCadastro).error = "Email inválido"
                    Toast.makeText(this, "Email inválido", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, preencha a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha.length < 6 -> {
                    findViewById<TextInputEditText>(R.id.txtSenhaCadastro).error = "Mínimo 6 caracteres"
                    Toast.makeText(this, "Senha deve ter pelo menos 6 caracteres", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                confirmaSenha.isEmpty() -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Campo obrigatório"
                    Toast.makeText(this, "Por favor, confirme a senha", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
                senha != confirmaSenha -> {
                    findViewById<TextInputEditText>(R.id.txtConfirmarSenha).error = "Senhas não coincidem"
                    Toast.makeText(this, "As senhas não coincidem", Toast.LENGTH_LONG).show()
                    erroValidacao = true
                }
            }

            // Se não houver erros, criar conta
            if (!erroValidacao) {
                try {
                    val db = DatabaseHelper(this)
                    val novoUser = User(nome = nome, email = email, password = senha)
                    val id = db.insertUser(novoUser)
                    if (id != -1L) {
                        // Mostrar AlertDialog de sucesso
                        AlertDialog.Builder(this)
                            .setTitle("Sucesso!")
                            .setMessage("Conta criada com sucesso! Agora faça login com suas credenciais.")
                            .setPositiveButton("OK") { _, _ ->
                                // Navegar para MainActivity (tela de login)
                                startActivity(Intent(this, MainActivity::class.java))
                                finish()
                            }
                            .setCancelable(false)
                            .show()
                    } else {
                        Toast.makeText(this, "Erro ao criar conta. Email pode estar duplicado.", Toast.LENGTH_LONG).show()
                    }
                } catch (e: Exception) {
                    Toast.makeText(this, "Erro: ${e.message}", Toast.LENGTH_LONG).show()
                }
            }
        }
    }
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.bottomnavigation.BottomNavigationView
import com.google.android.material.button.MaterialButton

class PerfilActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_perfil)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainPerfil)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        // Carregar dados do usuário logado
        carregarDadosUsuario()

        // Botão de logout
        findViewById<MaterialButton>(R.id.btnExcluirConta).setOnClickListener {
            mostrarDialogoLogout()
        }

        val bnvPerfil = findViewById<BottomNavigationView>(R.id.bnvPerfil)

        bnvPerfil.selectedItemId = R.id.menuPerfil
        bnvPerfil.setOnItemSelectedListener { item ->
            when (item.itemId) {
                R.id.menuProdutos -> {
                    startActivity(Intent(this, HomeActivity::class.java))
                    true
                }

                R.id.menuCarrinho -> {
                    startActivity(Intent(this, CarrinhoActivity::class.java))
                    true
                }

                R.id.menuPerfil -> true
                else -> false
            }
        }
    }

    private fun carregarDadosUsuario() {
        val sharedPref = getSharedPreferences("eco_verde_prefs", MODE_PRIVATE)
        val userId = sharedPref.getLong("user_id", -1L)

        if (userId != -1L) {
            try {
                val userDb = UserDatabaseHelper(this)
                val user = userDb.getUser(userId)

                if (user != null) {
                    // Exibir dados do usuário
                    findViewById<TextView>(R.id.txtNomePerfil).text = user.nome
                    findViewById<TextView>(R.id.txtEmailPerfil).text = user.email
                    findViewById<TextView>(R.id.txtInfoPerfil).text = "ID do usuário: ${user.id}"
                } else {
                    // Usuário não encontrado, fazer logout
                    fazer_logout()
                }
            } catch (e: Exception) {
                Toast.makeText(this, "Erro ao carregar perfil: ${e.message}", Toast.LENGTH_LONG).show()
            }
        } else {
            // Nenhum usuário logado
            fazer_logout()
        }
    }

    private fun mostrarDialogoLogout() {
        AlertDialog.Builder(this)
            .setTitle("Logout")
            .setMessage("Tem certeza que deseja sair?")
            .setPositiveButton("Sim") { _, _ ->
                fazer_logout()
            }
            .setNegativeButton("Cancelar", null)
            .show()
    }

    private fun fazer_logout() {
        // Limpar dados do usuário
        val sharedPref = getSharedPreferences("eco_verde_prefs", MODE_PRIVATE)
        with(sharedPref.edit()) {
            remove("user_id")
            remove("user_name")
            remove("user_email")
            apply()
        }

        // Voltar para MainActivity
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }
}

package com.example.projetomobile

import android.content.Intent
import android.os.Bundle
import android.text.InputType
import android.widget.EditText
import android.widget.LinearLayout
import android.widget.TextView
import android.widget.Toast
import androidx.activity.enableEdgeToEdge
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.core.view.ViewCompat
import androidx.core.view.WindowInsetsCompat
import com.google.android.material.bottomnavigation.BottomNavigationView
import com.google.android.material.button.MaterialButton

class PerfilActivity : AppCompatActivity() {

    private val sharedPrefsName = "eco_verde_prefs"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContentView(R.layout.activity_perfil)
        ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.mainPerfil)) { view, insets ->
            val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars())
            view.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom)
            insets
        }

        // Carregar dados do usuário logado
        carregarDadosUsuario()

        // Botão de alteração de senha
        findViewById<MaterialButton>(R.id.btnEditarPerfil).setOnClickListener {
            mostrarDialogoAlterarSenha()
        }

        // Botão de exclusão da conta
        findViewById<MaterialButton>(R.id.btnExcluirConta).setOnClickListener {
            mostrarDialogoExcluirConta()
        }

        val bnvPerfil = findViewById<BottomNavigationView>(R.id.bnvPerfil)

        bnvPerfil.selectedItemId = R.id.menuPerfil
        bnvPerfil.setOnItemSelectedListener { item ->
            when (item.itemId) {
                R.id.menuProdutos -> {
                    startActivity(Intent(this, HomeActivity::class.java))
                    true
                }

                R.id.menuCarrinho -> {
                    startActivity(Intent(this, CarrinhoActivity::class.java))
                    true
                }

                R.id.menuPerfil -> true
                else -> false
            }
        }
    }

    private fun carregarDadosUsuario() {
        val sharedPref = getSharedPreferences(sharedPrefsName, MODE_PRIVATE)
        val userId = sharedPref.getLong("user_id", -1L)

        if (userId != -1L) {
            try {
                val userDb = UserDatabaseHelper(this)
                val user = userDb.getUser(userId)

                if (user != null) {
                    // Exibir dados do usuário
                    findViewById<TextView>(R.id.txtNomePerfil).text = user.nome
                    findViewById<TextView>(R.id.txtEmailPerfil).text = user.email
                    findViewById<TextView>(R.id.txtInfoPerfil).text = "ID do usuário: ${user.id}"
                } else {
                    // Usuário não encontrado, fazer logout
                    limparSessaoEIrLogin()
                }
            } catch (e: Exception) {
                Toast.makeText(this, "Erro ao carregar perfil: ${e.message}", Toast.LENGTH_LONG).show()
            }
        } else {
            // Nenhum usuário logado
            limparSessaoEIrLogin()
        }
    }

    private fun mostrarDialogoAlterarSenha() {
        val sharedPref = getSharedPreferences(sharedPrefsName, MODE_PRIVATE)
        val userId = sharedPref.getLong("user_id", -1L)

        if (userId == -1L) {
            limparSessaoEIrLogin()
            return
        }

        val layout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(16, 16, 16, 0)
        }

        val senhaAtualInput = EditText(this).apply {
            hint = getString(R.string.hint_senha_atual)
            inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
        }
        val novaSenhaInput = EditText(this).apply {
            hint = getString(R.string.hint_nova_senha)
            inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
        }
        val confirmarSenhaInput = EditText(this).apply {
            hint = getString(R.string.hint_confirmar_nova_senha)
            inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
        }

        layout.addView(senhaAtualInput)
        layout.addView(novaSenhaInput)
        layout.addView(confirmarSenhaInput)

        AlertDialog.Builder(this)
            .setTitle(R.string.titulo_alterar_senha)
            .setView(layout)
            .setPositiveButton(R.string.dialog_btn_salvar) { _, _ ->
                val senhaAtual = senhaAtualInput.text.toString()
                val novaSenha = novaSenhaInput.text.toString()
                val confirmarSenha = confirmarSenhaInput.text.toString()

                when {
                    senhaAtual.isBlank() -> {
                        Toast.makeText(this, R.string.erro_senha_atual_vazia, Toast.LENGTH_LONG).show()
                    }
                    novaSenha.length < 6 -> {
                        Toast.makeText(this, R.string.erro_senha_curta, Toast.LENGTH_LONG).show()
                    }
                    novaSenha != confirmarSenha -> {
                        Toast.makeText(this, R.string.erro_senha_diferente, Toast.LENGTH_LONG).show()
                    }
                    else -> {
                        val result = UserDatabaseHelper(this).changePassword(userId, senhaAtual, novaSenha)
                        when (result) {
                            UserDatabaseHelper.PasswordChangeResult.SUCCESS -> {
                                Toast.makeText(this, R.string.msg_senha_atualizada, Toast.LENGTH_LONG).show()
                            }
                            UserDatabaseHelper.PasswordChangeResult.INVALID_CURRENT_PASSWORD -> {
                                Toast.makeText(this, R.string.erro_senha_atual_incorreta, Toast.LENGTH_LONG).show()
                            }
                            UserDatabaseHelper.PasswordChangeResult.USER_NOT_FOUND -> {
                                Toast.makeText(this, R.string.erro_usuario_nao_encontrado, Toast.LENGTH_LONG).show()
                                limparSessaoEIrLogin()
                            }
                            UserDatabaseHelper.PasswordChangeResult.UPDATE_FAILED -> {
                                Toast.makeText(this, R.string.erro_salvar_senha, Toast.LENGTH_LONG).show()
                            }
                        }
                    }
                }
            }
            .setNegativeButton(R.string.dialog_btn_cancelar, null)
            .show()
    }

    private fun mostrarDialogoExcluirConta() {
        AlertDialog.Builder(this)
            .setTitle(R.string.dialog_excluir_titulo)
            .setMessage(R.string.dialog_excluir_mensagem)
            .setPositiveButton(R.string.dialog_excluir_confirmar) { _, _ ->
                excluirContaAtual()
            }
            .setNegativeButton(R.string.dialog_excluir_cancelar, null)
            .show()
    }

    private fun excluirContaAtual() {
        val sharedPref = getSharedPreferences(sharedPrefsName, MODE_PRIVATE)
        val userId = sharedPref.getLong("user_id", -1L)

        if (userId != -1L) {
            val rows = UserDatabaseHelper(this).deleteUser(userId)
            if (rows > 0) {
                Toast.makeText(this, R.string.msg_conta_excluida, Toast.LENGTH_LONG).show()
            } else {
                Toast.makeText(this, R.string.erro_excluir_conta, Toast.LENGTH_LONG).show()
            }
        }

        limparSessaoEIrLogin()
    }

    private fun limparSessaoEIrLogin() {
        val sharedPref = getSharedPreferences(sharedPrefsName, MODE_PRIVATE)
        with(sharedPref.edit()) {
            remove("user_id")
            remove("user_name")
            remove("user_email")
            apply()
        }

        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }
}

package com.example.projetomobile
import android.content.ContentValues import android.content.Context
/** * DatabaseHelper específico para operações CRUD de User. * Delegado pela classe DatabaseHelper que gerencia schema e versionamento. */ class UserDatabaseHelper(context: Context) { private val dbHelper = DatabaseHelper(context)
/** * Insere um novo usuário no banco de dados. * @param user Objeto User a ser inserido * @return ID do usuário inserido, ou -1 se falhar */ fun insertUser(user: User): Long { val db = dbHelper.writableDatabase val values = ContentValues().apply { put(DatabaseHelper.USER_COL_NOME, user.nome) put(DatabaseHelper.USER_COL_EMAIL, user.email) put(DatabaseHelper.USER_COL_PASSWORD, hashPassword(user.password)) put(DatabaseHelper.USER_COL_ROLE, user.role) } val id = db.insert(DatabaseHelper.TABLE_USER, null, values) user.id = if (id == -1L) null else id db.close() return id }
/** * Obtém um usuário pelo ID. * @param id ID do usuário * @return Objeto User ou null se não encontrado */ fun getUser(id: Long): User? { val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_USER, arrayOf( DatabaseHelper.USER_COL_ID, DatabaseHelper.USER_COL_NOME, DatabaseHelper.USER_COL_EMAIL, DatabaseHelper.USER_COL_PASSWORD, DatabaseHelper.USER_COL_ROLE ), "${DatabaseHelper.USER_COL_ID} = ?", arrayOf(id.toString()), null, null, null ) var user: User? = null if (cursor.moveToFirst()) { val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME)) val email = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL)) val password = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD)) val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE)) user = User(uid, nome, email, password, role) } cursor.close() db.close() return user }
/** * Obtém todos os usuários do banco. * @return Lista de usuários ordenados por nome */ fun getAllUsers(): List<User> { val users = mutableListOf<User>() val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_USER, arrayOf( DatabaseHelper.USER_COL_ID, DatabaseHelper.USER_COL_NOME, DatabaseHelper.USER_COL_EMAIL, DatabaseHelper.USER_COL_PASSWORD, DatabaseHelper.USER_COL_ROLE ), null, null, null, null, "${DatabaseHelper.USER_COL_NOME} ASC" ) if (cursor.moveToFirst()) { do { val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME)) val email = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL)) val password = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD)) val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE)) users.add(User(uid, nome, email, password, role)) } while (cursor.moveToNext()) } cursor.close() db.close() return users }
/** * Autentica um usuário validando email e senha. * @param email Email do usuário * @param password Senha em texto plano * @return Objeto User se autenticado com sucesso, null caso contrário */ fun authenticateUser(email: String, password: String): User? { val db = dbHelper.readableDatabase val cursor = db.query( DatabaseHelper.TABLE_USER, arrayOf( DatabaseHelper.USER_COL_ID, DatabaseHelper.USER_COL_NOME, DatabaseHelper.USER_COL_EMAIL, DatabaseHelper.USER_COL_PASSWORD, DatabaseHelper.USER_COL_ROLE ), "${DatabaseHelper.USER_COL_EMAIL} = ?", arrayOf(email), null, null, null )
var user: User? = null if (cursor.moveToFirst()) { val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID)) val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME)) val userEmail = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL)) val hashedPassword = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD)) val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE))
// Verificar se a senha corresponde à hash armazenada if (hashPassword(password) == hashedPassword) { user = User(uid, nome, userEmail, hashedPassword, role) } } cursor.close() db.close() return user }
/** * Atualiza os dados de um usuário. * @param user Objeto User com dados atualizados * @return Número de linhas afetadas */ fun updateUser(user: User): Int { val db = dbHelper.writableDatabase val values = ContentValues().apply { put(DatabaseHelper.USER_COL_NOME, user.nome) put(DatabaseHelper.USER_COL_EMAIL, user.email) put(DatabaseHelper.USER_COL_PASSWORD, hashPassword(user.password)) put(DatabaseHelper.USER_COL_ROLE, user.role) } val rowsAffected = db.update( DatabaseHelper.TABLE_USER, values, "${DatabaseHelper.USER_COL_ID} = ?", arrayOf(user.id.toString()) ) db.close() return rowsAffected }
/** * Deleta um usuário pelo ID. * @param id ID do usuário a deletar * @return Número de linhas afetadas */ fun deleteUser(id: Long): Int { val db = dbHelper.writableDatabase val rowsAffected = db.delete( DatabaseHelper.TABLE_USER, "${DatabaseHelper.USER_COL_ID} = ?", arrayOf(id.toString()) ) db.close() return rowsAffected }
// Simple SHA-256 hash for password storage private fun hashPassword(password: String): String { val md = java.security.MessageDigest.getInstance("SHA-256") val bytes = md.digest(password.toByteArray(Charsets.UTF_8)) return bytes.joinToString("") { "%02x".format(it) } } }

package com.example.projetomobile

import android.content.ContentValues
import android.content.Context

/**
 * DatabaseHelper específico para operações CRUD de User.
 * Delegado pela classe DatabaseHelper que gerencia schema e versionamento.
 */
class UserDatabaseHelper(context: Context) {
    private val dbHelper = DatabaseHelper(context)

    enum class PasswordChangeResult {
        SUCCESS,
        USER_NOT_FOUND,
        INVALID_CURRENT_PASSWORD,
        UPDATE_FAILED
    }

    /**
     * Insere um novo usuário no banco de dados.
     * @param user Objeto User a ser inserido
     * @return ID do usuário inserido, ou -1 se falhar
     */
    fun insertUser(user: User): Long {
        val db = dbHelper.writableDatabase
        val values = ContentValues().apply {
            put(DatabaseHelper.USER_COL_NOME, user.nome)
            put(DatabaseHelper.USER_COL_EMAIL, user.email)
            put(DatabaseHelper.USER_COL_PASSWORD, hashPassword(user.password))
            put(DatabaseHelper.USER_COL_ROLE, user.role)
        }
        val id = db.insert(DatabaseHelper.TABLE_USER, null, values)
        user.id = if (id == -1L) null else id
        db.close()
        return id
    }

    /**
     * Obtém um usuário pelo ID.
     * @param id ID do usuário
     * @return Objeto User ou null se não encontrado
     */
    fun getUser(id: Long): User? {
        val db = dbHelper.readableDatabase
        val cursor = db.query(
            DatabaseHelper.TABLE_USER,
            arrayOf(
                DatabaseHelper.USER_COL_ID,
                DatabaseHelper.USER_COL_NOME,
                DatabaseHelper.USER_COL_EMAIL,
                DatabaseHelper.USER_COL_PASSWORD,
                DatabaseHelper.USER_COL_ROLE
            ),
            "${DatabaseHelper.USER_COL_ID} = ?",
            arrayOf(id.toString()),
            null,
            null,
            null
        )
        var user: User? = null
        if (cursor.moveToFirst()) {
            val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID))
            val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME))
            val email = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL))
            val password = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD))
            val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE))
            user = User(uid, nome, email, password, role)
        }
        cursor.close()
        db.close()
        return user
    }

    /**
     * Obtém todos os usuários do banco.
     * @return Lista de usuários ordenados por nome
     */
    fun getAllUsers(): List<User> {
        val users = mutableListOf<User>()
        val db = dbHelper.readableDatabase
        val cursor = db.query(
            DatabaseHelper.TABLE_USER,
            arrayOf(
                DatabaseHelper.USER_COL_ID,
                DatabaseHelper.USER_COL_NOME,
                DatabaseHelper.USER_COL_EMAIL,
                DatabaseHelper.USER_COL_PASSWORD,
                DatabaseHelper.USER_COL_ROLE
            ),
            null,
            null,
            null,
            null,
            "${DatabaseHelper.USER_COL_NOME} ASC"
        )
        if (cursor.moveToFirst()) {
            do {
                val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID))
                val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME))
                val email = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL))
                val password = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD))
                val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE))
                users.add(User(uid, nome, email, password, role))
            } while (cursor.moveToNext())
        }
        cursor.close()
        db.close()
        return users
    }

    /**
     * Autentica um usuário validando email e senha.
     * @param email Email do usuário
     * @param password Senha em texto plano
     * @return Objeto User se autenticado com sucesso, null caso contrário
     */
    fun authenticateUser(email: String, password: String): User? {
        val db = dbHelper.readableDatabase
        val cursor = db.query(
            DatabaseHelper.TABLE_USER,
            arrayOf(
                DatabaseHelper.USER_COL_ID,
                DatabaseHelper.USER_COL_NOME,
                DatabaseHelper.USER_COL_EMAIL,
                DatabaseHelper.USER_COL_PASSWORD,
                DatabaseHelper.USER_COL_ROLE
            ),
            "${DatabaseHelper.USER_COL_EMAIL} = ?",
            arrayOf(email),
            null,
            null,
            null
        )

        var user: User? = null
        if (cursor.moveToFirst()) {
            val uid = cursor.getLong(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ID))
            val nome = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_NOME))
            val userEmail = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_EMAIL))
            val hashedPassword = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD))
            val role = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_ROLE))

            // Verificar se a senha corresponde à hash armazenada
            if (hashPassword(password) == hashedPassword) {
                user = User(uid, nome, userEmail, hashedPassword, role)
            }
        }
        cursor.close()
        db.close()
        return user
    }

    /**
     * Atualiza os dados de um usuário.
     * @param user Objeto User com dados atualizados
     * @return Número de linhas afetadas
     */
    fun updateUser(user: User): Int {
        val db = dbHelper.writableDatabase
        val values = ContentValues().apply {
            put(DatabaseHelper.USER_COL_NOME, user.nome)
            put(DatabaseHelper.USER_COL_EMAIL, user.email)
            put(DatabaseHelper.USER_COL_PASSWORD, hashPassword(user.password))
            put(DatabaseHelper.USER_COL_ROLE, user.role)
        }
        val rowsAffected = db.update(
            DatabaseHelper.TABLE_USER,
            values,
            "${DatabaseHelper.USER_COL_ID} = ?",
            arrayOf(user.id.toString())
        )
        db.close()
        return rowsAffected
    }

    /**
     * Atualiza somente a senha do usuário, validando a senha atual.
     * @param userId ID do usuário
     * @param currentPassword Senha atual em texto plano
     * @param newPassword Nova senha em texto plano
     * @return Resultado da operação
     */
    fun changePassword(userId: Long, currentPassword: String, newPassword: String): PasswordChangeResult {
        val db = dbHelper.writableDatabase
        val cursor = db.query(
            DatabaseHelper.TABLE_USER,
            arrayOf(DatabaseHelper.USER_COL_PASSWORD),
            "${DatabaseHelper.USER_COL_ID} = ?",
            arrayOf(userId.toString()),
            null,
            null,
            null
        )

        try {
            if (!cursor.moveToFirst()) {
                return PasswordChangeResult.USER_NOT_FOUND
            }

            val storedPassword = cursor.getString(cursor.getColumnIndexOrThrow(DatabaseHelper.USER_COL_PASSWORD))
            if (hashPassword(currentPassword) != storedPassword) {
                return PasswordChangeResult.INVALID_CURRENT_PASSWORD
            }

            val values = ContentValues().apply {
                put(DatabaseHelper.USER_COL_PASSWORD, hashPassword(newPassword))
            }

            val rowsAffected = db.update(
                DatabaseHelper.TABLE_USER,
                values,
                "${DatabaseHelper.USER_COL_ID} = ?",
                arrayOf(userId.toString())
            )

            return if (rowsAffected > 0) {
                PasswordChangeResult.SUCCESS
            } else {
                PasswordChangeResult.UPDATE_FAILED
            }
        } finally {
            cursor.close()
            db.close()
        }
    }

    /**
     * Deleta um usuário pelo ID.
     * @param id ID do usuário a deletar
     * @return Número de linhas afetadas
     */
    fun deleteUser(id: Long): Int {
        val db = dbHelper.writableDatabase
        val rowsAffected = db.delete(
            DatabaseHelper.TABLE_USER,
            "${DatabaseHelper.USER_COL_ID} = ?",
            arrayOf(id.toString())
        )
        db.close()
        return rowsAffected
    }

    // Simple SHA-256 hash for password storage
    private fun hashPassword(password: String): String {
        val md = java.security.MessageDigest.getInstance("SHA-256")
        val bytes = md.digest(password.toByteArray(Charsets.UTF_8))
        return bytes.joinToString("") { "%02x".format(it) }
    }
}
